patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index a2ab5d966640..53c51800759e 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -1795,7 +1795,7 @@ generateInstLaneVectorFromOperand(ArrayRef<InstLane> Item, int Op) {
 /// Detect concat of multiple values into a vector
 static bool isFreeConcat(ArrayRef<InstLane> Item,
                          const TargetTransformInfo &TTI) {
-  auto *Ty = cast<FixedVectorType>(Item.front().first->get()->getType());
+  auto *Ty = dyn_cast<FixedVectorType>(Item.front().first->get()->getType()); if (!Ty) return false;
   unsigned NumElts = Ty->getNumElements();
   if (Item.size() == NumElts || NumElts == 1 || Item.size() % NumElts != 0)
     return false;
@@ -1951,7 +1951,7 @@ bool VectorCombine::foldShuffleToIdentity(Instruction &I) {

     // Look for an identity value.
     if (FrontLane == 0 &&
-        cast<FixedVectorType>(FrontU->get()->getType())->getNumElements() ==
+        isa<FixedVectorType>(FrontU->get()->getType()) && cast<FixedVectorType>(FrontU->get()->getType())->getNumElements() ==
             Ty->getNumElements() &&
         all_of(drop_begin(enumerate(Item)), [IsEquiv, Item](const auto &E) {
           Value *FrontV = Item.front().first->get();
@@ -1963,7 +1963,7 @@ bool VectorCombine::foldShuffleToIdentity(Instruction &I) {
     }
     // Look for constants, for the moment only supporting constant splats.
     if (auto *C = dyn_cast<Constant>(FrontU);
-        C && C->getSplatValue() &&
+        C && C->getType()->isVectorTy() && C->getSplatValue() &&
         all_of(drop_begin(Item), [Item](InstLane &IL) {
           Value *FrontV = Item.front().first->get();
           Use *U = IL.first;

